import{_ as o,o as n,c as a,ag as s}from"./chunks/framework.BbyMWZAR.js";const g=JSON.parse('{"title":"Webpack 的工作原理与构建流程","description":"","frontmatter":{"title":"Webpack 的工作原理与构建流程","difficulty":"medium","tags":["Webpack","打包器","构建流程"],"estimate":15},"headers":[],"relativePath":"domains/arch/qa/qa-01-webpack-principle.md","filePath":"domains/arch/qa/qa-01-webpack-principle.md","lastUpdated":1783504823000}'),t={name:"domains/arch/qa/qa-01-webpack-principle.md"};function l(r,e,c,i,d,p){return n(),a("div",null,[...e[0]||(e[0]=[s(`<h1 id="问答-01-进阶-webpack-的工作原理与构建流程" tabindex="-1">问答 01（进阶）：Webpack 的工作原理与构建流程 <a class="header-anchor" href="#问答-01-进阶-webpack-的工作原理与构建流程" aria-label="Permalink to &quot;问答 01（进阶）：Webpack 的工作原理与构建流程&quot;">​</a></h1><h2 id="题目" tabindex="-1">题目 <a class="header-anchor" href="#题目" aria-label="Permalink to &quot;题目&quot;">​</a></h2><p>请说明 Webpack 中的核心概念（entry / output / loader / plugin / chunk / module）以及一次完整构建的流程。</p><h2 id="参考答案" tabindex="-1">参考答案 <a class="header-anchor" href="#参考答案" aria-label="Permalink to &quot;参考答案&quot;">​</a></h2><p><strong>核心概念</strong></p><ul><li><strong>entry</strong>：入口文件，构建的起点。SPA 一般一个，MPA 多个。</li><li><strong>output</strong>：产物配置（<code>path</code> / <code>filename</code> / <code>chunkFilename</code> / <code>publicPath</code>）。</li><li><strong>module</strong>：Webpack 眼里一切资源都是模块，<code>.js</code> / <code>.css</code> / <code>.png</code> / <code>.vue</code> 都是。</li><li><strong>loader</strong>：模块级&quot;翻译器&quot;，把非 JS 或需要转换的资源翻译成 JS 可识别的模块（<code>babel-loader</code>、<code>css-loader</code>、<code>ts-loader</code>）。<strong>从右到左、从下到上</strong>执行。</li><li><strong>plugin</strong>：插件，作用于构建全生命周期（tap 到 compiler / compilation 各种 hooks），做资源注入、产物变换、优化、报告等。</li><li><strong>chunk</strong>：构建过程中的资源组，最终会输出为 bundle 文件。入口 chunk、异步 chunk（<code>import()</code>）、<code>splitChunks</code> 抽出来的公共 chunk。</li><li><strong>bundle</strong>：最终写到磁盘的产物文件，一个 chunk 可能对应一个或多个 bundle（含 map 文件）。</li></ul><p><strong>构建流程（简化）</strong></p><ol><li><strong>初始化参数</strong>：合并 CLI 参数与配置文件，得到最终 options。</li><li><strong>创建 Compiler</strong>：<code>new Compiler(options)</code>，注册配置里的 plugins（<code>plugin.apply(compiler)</code>）。</li><li><strong>触发 <code>run</code></strong>：进入 <code>beforeRun</code>、<code>run</code>、<code>beforeCompile</code>、<code>compile</code> 等 hook。</li><li><strong>创建 Compilation</strong>：一次构建对应一个 Compilation 对象，管理本次的模块图、chunk 图、资源。</li><li><strong>从 entry 开始构建模块</strong>：递归解析 → 交给 loader 链翻译 → 再解析 AST 找到依赖 → 继续递归，形成<strong>模块依赖图</strong>。</li><li><strong>组装 chunk</strong>：根据入口和 <code>splitChunks</code> 规则把模块分组到 chunk。</li><li><strong>生成资源</strong>：每个 chunk 走 template（<code>JavascriptModulesPlugin</code> 等）拼装成最终代码，插入运行时（webpack runtime）。</li><li><strong>优化</strong>：tree-shaking、mangle、minify（<code>TerserPlugin</code>），<code>ModuleConcatenationPlugin</code> 合并作用域，Content hash 计算。</li><li><strong>emit</strong>：把资源写入 <code>output.path</code>；<code>afterEmit</code> / <code>done</code> 等 hook 收尾。</li></ol><p><strong>产物结构（大致）</strong></p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>dist/</span></span>
<span class="line"><span>  runtime~main.hash.js   // 运行时（可选拆分）</span></span>
<span class="line"><span>  main.hash.js           // 入口 chunk</span></span>
<span class="line"><span>  vendors.hash.js        // splitChunks 抽出的公共依赖</span></span>
<span class="line"><span>  0.async.hash.js        // 动态 import 生成的 chunk</span></span>
<span class="line"><span>  main.hash.js.map       // sourcemap</span></span>
<span class="line"><span>  assets/*.png ...       // 静态资源</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br></div></div><h2 id="追问-1-import-a-js-是怎么工作的-运行时做了什么" tabindex="-1">追问 1：<code>import(&#39;./a.js&#39;)</code> 是怎么工作的？运行时做了什么？ <a class="header-anchor" href="#追问-1-import-a-js-是怎么工作的-运行时做了什么" aria-label="Permalink to &quot;追问 1：\`import(&#39;./a.js&#39;)\` 是怎么工作的？运行时做了什么？&quot;">​</a></h2><p><strong>答</strong>：</p><ul><li>编译阶段 Webpack 识别到 <code>import()</code>，把 <code>a.js</code> 切成独立 chunk（异步 chunk），生成对应 bundle。</li><li>运行时 Webpack 注入了 <code>__webpack_require__.e(chunkId)</code>： <ol><li>通过 <code>document.createElement(&#39;script&#39;)</code> 动态加载对应 bundle URL（<code>publicPath + chunkFilename</code>）；</li><li>加载完成后调用 <code>webpackChunk</code> 全局注册的回调，注入 chunk 到模块图；</li><li>返回一个 Promise，<code>await import()</code> 拿到模块的 exports。</li></ol></li><li>好处：<strong>按需加载</strong>，减少首屏 bundle 体积；配合 preload / prefetch magic comment 可以进一步优化。</li></ul><h2 id="追问-2-loader-和-plugin-到底什么区别-可以互相替代吗" tabindex="-1">追问 2：Loader 和 Plugin 到底什么区别？可以互相替代吗？ <a class="header-anchor" href="#追问-2-loader-和-plugin-到底什么区别-可以互相替代吗" aria-label="Permalink to &quot;追问 2：Loader 和 Plugin 到底什么区别？可以互相替代吗？&quot;">​</a></h2><p><strong>答</strong>：</p><ul><li><strong>Loader</strong>：作用于<strong>单个模块的源码翻译</strong>，输入源代码字符串，输出转换后的字符串或 AST。范围窄，一次只处理一个模块。</li><li><strong>Plugin</strong>：作用于<strong>整个构建过程</strong>，通过 <code>compiler.hooks.*</code> / <code>compilation.hooks.*</code> 订阅事件，能改整个模块图、chunk 图，注入资源、生成额外文件。</li><li>二者<strong>互补而非替代</strong>： <ul><li>把 SCSS 编译成 CSS → loader（<code>sass-loader</code>）；</li><li>把所有 CSS 从 JS 里抽出成独立文件 → plugin（<code>MiniCssExtractPlugin</code>）；</li><li>语法转换 → loader；产物压缩、注入 HTML、生成 manifest → plugin。</li></ul></li><li>简单判断：<strong>能不能只看单个文件解决问题</strong>，能就写 loader；<strong>需要跨模块协作或生成新产物</strong>，写 plugin。</li></ul><h2 id="追问-3-webpack-5-相比-4-有哪些-值得说-的改进" tabindex="-1">追问 3：Webpack 5 相比 4 有哪些&quot;值得说&quot;的改进？ <a class="header-anchor" href="#追问-3-webpack-5-相比-4-有哪些-值得说-的改进" aria-label="Permalink to &quot;追问 3：Webpack 5 相比 4 有哪些&quot;值得说&quot;的改进？&quot;">​</a></h2><p><strong>答</strong>：</p><ul><li><strong>持久化缓存</strong>（<code>cache: { type: &#39;filesystem&#39; }</code>）：把模块解析、生成结果写到磁盘，二次构建从秒级降到毫秒级。是最有感知的提升。</li><li><strong>Module Federation</strong>：跨应用共享代码/组件的运行时协议，微前端里 remote-entry 就是这个基础。</li><li><strong>原生资源模块类型</strong>（<code>asset</code> / <code>asset/resource</code> / <code>asset/inline</code> / <code>asset/source</code>）：替代 <code>file-loader</code> / <code>url-loader</code> / <code>raw-loader</code>。</li><li><strong>Tree-shaking 更强</strong>：支持嵌套 export、<code>sideEffects</code> 更精细、CSS tree-shaking（配合插件）。</li><li><strong>Deterministic module/chunk ID</strong>：默认稳定的 ID，长期缓存友好。</li><li><strong>移除 Node.js polyfill 默认注入</strong>：显式配置 <code>resolve.fallback</code>，产物更小但升级时需注意。</li></ul><h2 id="参考资料" tabindex="-1">参考资料 <a class="header-anchor" href="#参考资料" aria-label="Permalink to &quot;参考资料&quot;">​</a></h2><blockquote><p>深入阅读请从标注 <strong>首选</strong> 的来源开始；本领域完整索引见 <a href="/engineer/handbook/domains/arch/RESOURCES">工程架构 参考资料</a>。</p></blockquote><ul><li><strong>首选</strong> — <a href="https://webpack.js.org/concepts/" target="_blank" rel="noreferrer">Webpack Concepts</a>：entry、output、loader、plugin 与 chunk 的核心概念，Webpack 原理题的官方起点。</li><li><a href="https://webpack.js.org/concepts/entry-points/" target="_blank" rel="noreferrer">Webpack: Entry and Context</a>：多入口、动态入口与依赖图如何从 entry 展开。</li><li><a href="https://webpack.js.org/concepts/output/" target="_blank" rel="noreferrer">Webpack: Output</a>：<code>filename</code>、<code>chunkFilename</code>、<code>publicPath</code> 与运行时加载 chunk 的关系。</li></ul>`,22)])])}const h=o(t,[["render",l]]);export{g as __pageData,h as default};
